def is_prime(n):
    """जांचें कि कोई संख्या अभाज्य है या नहीं।"""
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def is_multiply_prime(a):
    """जांचें कि कोई संख्या तीन अभाज्य संख्याओं का गुणनफल है या नहीं।"""
    factors = []
    for i in range(2, int(a**0.5) + 1):
        if a % i == 0:
            factors.append(i)
            if i != a // i:
                factors.append(a // i)
    factors = list(set(factors))
    factors = [f for f in factors if is_prime(f)]
    factors.sort()
    for i in range(len(factors)):
        for j in range(i, len(factors)):
            for k in range(j, len(factors)):
                if factors[i] * factors[j] * factors[k] == a:
                    return True
    return False

# उदाहरण उपयोग
print(is_multiply_prime(30))  # True
print(is_multiply_prime(31))  # False
```
यह अनुकूलित दृष्टिकोण पहले संख्या के कारकों की सूची बनाता है और फिर जांचता है कि क्या उनमें से कोई तीन अभाज्य हैं जिनका गुणनफल दी गई संख्या के बराबर है। यह दृष्टिकोण अधिक कुशल है क्योंकि इसमें अनावश्यक गणनाओं से बचा जाता है।
